import {
  makeFunctionReference,
  mutationGeneric,
  queryGeneric,
} from "convex/server";
import { v } from "convex/values";

export const getTermsPageData = queryGeneric({
  args: {
    token: v.string(),
  },
  returns: v.union(
    v.null(),
    v.object({
      customer_mobile: v.string(),
      participant_count: v.number(),
      purchase_status: v.union(
        v.literal("pending_terms"),
        v.literal("confirmation_sent"),
        v.literal("terms_accepted"),
        v.literal("cancelled")
      ),
      class_name: v.optional(v.string()),
      terms_version: v.string(),
      terms_content: v.string(),
      sessions: v.array(
        v.object({
          session_id: v.string(),
          class_id: v.string(),
          class_name: v.string(),
          location: v.string(),
          date: v.string(),
          time: v.string(),
          available_quota: v.number(),
        })
      ),
    })
  ),
  handler: async (ctx, args) => {
    const purchase = await ctx.db
      .query("purchases")
      .withIndex("by_token", (q) => q.eq("token", args.token))
      .first();

    if (!purchase || purchase.status === "cancelled") {
      return null;
    }

    const currentTerms = await ctx.db
      .query("terms_versions")
      .withIndex("by_is_current", (q) => q.eq("is_current", true))
      .first();

    if (!currentTerms) {
      return null;
    }

    const classDocs = new Map<string, string>();
    if (purchase.class_id) {
      const purchaseClass = await ctx.db
        .query("classes")
        .withIndex("by_class_id", (q) => q.eq("class_id", purchase.class_id!))
        .first();
      if (purchaseClass) {
        classDocs.set(purchaseClass.class_id, purchaseClass.name);
      }
    }

    const rawSessions = purchase.class_id
      ? await ctx.db
          .query("sessions")
          .withIndex("by_class_id", (q) => q.eq("class_id", purchase.class_id!))
          .collect()
      : await ctx.db.query("sessions").collect();

    const classIds = new Set(rawSessions.map((session) => session.class_id));
    for (const classId of classIds) {
      if (!classDocs.has(classId)) {
        const classRecord = await ctx.db
          .query("classes")
          .withIndex("by_class_id", (q) => q.eq("class_id", classId))
          .first();
        if (classRecord) {
          classDocs.set(classId, classRecord.name);
        }
      }
    }

    const sessions = rawSessions
      .filter((session) => session.status === "scheduled")
      .map((session) => {
        const availableQuota = Math.max(
          session.quota_defined - session.quota_used,
          0
        );
        return {
          session_id: session.session_id,
          class_id: session.class_id,
          class_name: classDocs.get(session.class_id) ?? "Unknown class",
          location: session.location,
          date: session.date,
          time: session.time,
          available_quota: availableQuota,
        };
      })
      .filter((session) => session.available_quota > 0)
      .sort((left, right) => {
        const leftDateTime = `${left.date}T${left.time}`;
        const rightDateTime = `${right.date}T${right.time}`;
        return leftDateTime.localeCompare(rightDateTime);
      });

    return {
      customer_mobile: purchase.customer_mobile,
      participant_count: purchase.participant_count,
      purchase_status: purchase.status,
      class_name: purchase.class_id
        ? (classDocs.get(purchase.class_id) ?? undefined)
        : undefined,
      terms_version: currentTerms.version,
      terms_content: currentTerms.content,
      sessions,
    };
  },
});

export const acceptTermsByToken = mutationGeneric({
  args: {
    token: v.string(),
    session_id: v.string(),
    accepted: v.boolean(),
  },
  returns: v.object({
    success: v.boolean(),
    error_message: v.optional(v.string()),
  }),
  handler: async (ctx, args) => {
    if (!args.accepted) {
      return {
        success: false,
        error_message: "Please accept the terms before submitting.",
      };
    }

    const purchase = await ctx.db
      .query("purchases")
      .withIndex("by_token", (q) => q.eq("token", args.token))
      .first();

    if (!purchase) {
      return {
        success: false,
        error_message: "Purchase token is invalid.",
      };
    }

    if (purchase.status === "terms_accepted") {
      return { success: true };
    }

    if (purchase.status === "cancelled") {
      return {
        success: false,
        error_message: "This purchase has been cancelled.",
      };
    }

    const session = await ctx.db
      .query("sessions")
      .withIndex("by_session_id", (q) => q.eq("session_id", args.session_id))
      .first();

    if (!session || session.status !== "scheduled") {
      return {
        success: false,
        error_message: "Selected session is not available.",
      };
    }

    const slotsRequired = Math.max(1, purchase.participant_count);
    const availableQuota = session.quota_defined - session.quota_used;
    if (availableQuota < slotsRequired) {
      return {
        success: false,
        error_message: "Selected session no longer has enough available quota.",
      };
    }

    const currentTerms = await ctx.db
      .query("terms_versions")
      .withIndex("by_is_current", (q) => q.eq("is_current", true))
      .first();

    if (!currentTerms) {
      return {
        success: false,
        error_message: "No active terms version is available.",
      };
    }

    const acceptedAt = Date.now();

    await ctx.db.patch(purchase._id, {
      class_id: session.class_id,
      session_id: session.session_id,
      status: "terms_accepted",
    });

    await ctx.db.patch(session._id, {
      quota_used: session.quota_used + slotsRequired,
    });

    const participantIds: string[] = [];
    for (let i = 0; i < slotsRequired; i += 1) {
      const participantId = crypto.randomUUID();
      participantIds.push(participantId);

      await ctx.db.insert("participants", {
        participant_id: participantId,
        purchase_id: purchase._id,
        session_id: session.session_id,
        mobile: purchase.customer_mobile,
        qr_code_data: participantId,
        terms_accepted_at: acceptedAt,
        terms_version_id: currentTerms._id,
        created_at: acceptedAt,
      });
    }

    await ctx.scheduler.runAfter(
      0,
      makeFunctionReference<"action">("participantLinks:sendParticipantLinks"),
      {
        customer_mobile: purchase.customer_mobile,
        participant_ids: participantIds,
      }
    );

    await ctx.db.insert("audit_logs", {
      action: "terms_accepted",
      entity_type: "purchase",
      entity_id: purchase.order_id,
      metadata: {
        token: purchase.token,
        session_id: session.session_id,
        class_id: session.class_id,
        accepted_at: acceptedAt,
        terms_version: currentTerms.version,
        participant_ids: participantIds,
      },
      created_at: acceptedAt,
    });

    return { success: true };
  },
});

"use client";

import { useMemo, useState } from "react";
import { useFormStatus } from "react-dom";

type SessionOption = {
  session_id: string;
  class_name: string;
  location: string;
  date: string;
  time: string;
  available_quota: number;
};

type TermsFormProps = {
  sessions: SessionOption[];
  submitAction: (formData: FormData) => void | Promise<void>;
  locked: boolean;
  errorMessage?: string;
  success: boolean;
};

export function TermsForm({
  sessions,
  submitAction,
  locked,
  errorMessage,
  success,
}: TermsFormProps) {
  const [sessionId, setSessionId] = useState("");
  const [accepted, setAccepted] = useState(false);
  const noAvailableSessions = sessions.length === 0;
  const disableForm = locked || noAvailableSessions || success;

  const helperMessage = useMemo(() => {
    if (success) {
      return "Terms accepted successfully.";
    }

    if (locked) {
      return "Terms have already been accepted for this purchase.";
    }

    if (noAvailableSessions) {
      return "No sessions currently have available quota.";
    }

    return undefined;
  }, [locked, noAvailableSessions, success]);

  return (
    <form action={submitAction} className="space-y-4 rounded-xl border border-zinc-200 p-5">
      <div className="space-y-2">
        <label htmlFor="session_id" className="block text-sm font-medium text-zinc-900">
          Select session
        </label>
        <select
          id="session_id"
          name="session_id"
          value={sessionId}
          onChange={(event) => setSessionId(event.target.value)}
          disabled={disableForm}
          className="w-full rounded-lg border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 disabled:cursor-not-allowed disabled:bg-zinc-100"
          required
        >
          <option value="">Choose a session</option>
          {sessions.map((session) => (
            <option key={session.session_id} value={session.session_id}>
              {session.class_name} - {session.location} ({session.date} {session.time}) | Available:{" "}
              {session.available_quota}
            </option>
          ))}
        </select>
      </div>

      <label className="flex items-start gap-2 text-sm text-zinc-900">
        <input
          type="checkbox"
          name="accepted"
          checked={accepted}
          onChange={(event) => setAccepted(event.target.checked)}
          disabled={disableForm}
          className="mt-0.5 h-4 w-4 rounded border-zinc-300"
        />
        <span>I have read and accept the terms</span>
      </label>

      {errorMessage ? (
        <p className="rounded-lg bg-red-50 px-3 py-2 text-sm text-red-700">{errorMessage}</p>
      ) : null}
      {helperMessage ? (
        <p className="rounded-lg bg-zinc-100 px-3 py-2 text-sm text-zinc-700">{helperMessage}</p>
      ) : null}

      <SubmitButton
        canSubmit={sessionId.length > 0 && accepted}
        disabled={disableForm}
      />
    </form>
  );
}

function SubmitButton({
  canSubmit,
  disabled,
}: {
  canSubmit: boolean;
  disabled: boolean;
}) {
  const { pending } = useFormStatus();
  const isDisabled = pending || disabled || !canSubmit;

  return (
    <button
      type="submit"
      disabled={isDisabled}
      className="w-full rounded-lg bg-zinc-900 px-4 py-2 text-sm font-medium text-white transition hover:bg-zinc-700 disabled:cursor-not-allowed disabled:bg-zinc-400"
    >
      {pending ? "Submitting..." : "Accept Terms"}
    </button>
  );
}

import { makeFunctionReference } from "convex/server";
import { redirect } from "next/navigation";

import { TermsForm } from "./terms-form";
import { createConvexHttpClient } from "@/lib/convexHttp";

type SearchParamValue = string | string[] | undefined;

type TermsPageProps = {
  searchParams: Promise<Record<string, SearchParamValue>>;
};

type TermsPageData = {
  customer_mobile: string;
  participant_count: number;
  purchase_status: "pending_terms" | "confirmation_sent" | "terms_accepted" | "cancelled";
  class_name?: string;
  terms_version: string;
  terms_content: string;
  sessions: Array<{
    session_id: string;
    class_id: string;
    class_name: string;
    location: string;
    date: string;
    time: string;
    available_quota: number;
  }>;
};

export default async function TermsPage({ searchParams }: TermsPageProps) {
  const params = await searchParams;
  const token = readSingleQueryParam(params.token);
  const status = readSingleQueryParam(params.status);
  const errorMessage = readSingleQueryParam(params.error);

  if (!token) {
    return (
      <main className="mx-auto min-h-screen w-full max-w-3xl px-4 py-10">
        <p className="rounded-lg bg-red-50 p-4 text-sm text-red-700">
          Missing purchase token. Please use the full link from your WhatsApp confirmation message.
        </p>
      </main>
    );
  }
  const tokenValue = token;

  const pageData = await loadTermsData(token);
  if (!pageData) {
    return (
      <main className="mx-auto min-h-screen w-full max-w-3xl px-4 py-10">
        <p className="rounded-lg bg-red-50 p-4 text-sm text-red-700">
          We could not find a valid purchase for this token.
        </p>
      </main>
    );
  }

  const submissionSucceeded = status === "success";
  const alreadyAccepted = pageData.purchase_status === "terms_accepted";

  async function submitTerms(formData: FormData) {
    "use server";

    const selectedSessionId = formData.get("session_id");
    const accepted = formData.get("accepted") === "on";

    if (typeof selectedSessionId !== "string" || selectedSessionId.length === 0) {
      redirect(
        `/terms?token=${encodeURIComponent(tokenValue)}&error=${encodeURIComponent("Please select a session.")}`
      );
    }

    const client = createConvexHttpClient();
    const result = await client.mutation(
      makeFunctionReference<"mutation">("terms:acceptTermsByToken"),
      {
        token: tokenValue,
        session_id: selectedSessionId,
        accepted,
      }
    );

    if (!result.success) {
      redirect(
        `/terms?token=${encodeURIComponent(tokenValue)}&error=${encodeURIComponent(
          result.error_message ?? "Unable to accept terms."
        )}`
      );
    }

    redirect(`/terms?token=${encodeURIComponent(tokenValue)}&status=success`);
  }

  return (
    <main className="mx-auto min-h-screen w-full max-w-3xl space-y-6 px-4 py-8">
      <section className="space-y-2">
        <h1 className="text-2xl font-semibold text-zinc-900">Terms Acceptance</h1>
        <p className="text-sm text-zinc-700">
          Confirm your class session and accept the terms to complete your registration.
        </p>
      </section>

      <section className="rounded-xl border border-zinc-200 p-5">
        <h2 className="text-lg font-medium text-zinc-900">Purchase details</h2>
        <dl className="mt-3 grid gap-2 text-sm text-zinc-700">
          <div>
            <dt className="font-medium text-zinc-900">Customer mobile</dt>
            <dd>{pageData.customer_mobile}</dd>
          </div>
          <div>
            <dt className="font-medium text-zinc-900">Participants</dt>
            <dd>{pageData.participant_count}</dd>
          </div>
          <div>
            <dt className="font-medium text-zinc-900">Class</dt>
            <dd>{pageData.class_name ?? "Will be selected based on your chosen session"}</dd>
          </div>
        </dl>
      </section>

      <section className="rounded-xl border border-zinc-200 p-5">
        <h2 className="text-lg font-medium text-zinc-900">
          Terms ({pageData.terms_version})
        </h2>
        <p className="mt-3 whitespace-pre-line text-sm leading-6 text-zinc-700">
          {pageData.terms_content}
        </p>
      </section>

      <TermsForm
        sessions={pageData.sessions}
        submitAction={submitTerms}
        locked={alreadyAccepted}
        success={submissionSucceeded}
        errorMessage={errorMessage}
      />
    </main>
  );
}

async function loadTermsData(token: string): Promise<TermsPageData | null> {
  try {
    const client = createConvexHttpClient();
    const result = await client.query(
      makeFunctionReference<"query">("terms:getTermsPageData"),
      { token }
    );
    return result;
  } catch {
    return null;
  }
}

function readSingleQueryParam(value: SearchParamValue): string | undefined {
  if (typeof value === "string") {
    return value;
  }
  if (Array.isArray(value)) {
    return value[0];
  }
  return undefined;
}

import { mutationGeneric } from "convex/server";
import { v } from "convex/values";
import bcrypt from "bcryptjs";

export const seedInitialData = mutationGeneric({
  args: {},
  returns: v.object({
    classes_created: v.number(),
    sessions_created: v.number(),
    terms_created: v.number(),
    admins_created: v.number(),
  }),
  handler: async (ctx) => {
    const now = Date.now();
    let classesCreated = 0;
    let sessionsCreated = 0;
    let termsCreated = 0;
    let adminsCreated = 0;

    const classSeeds = [
      {
        class_id: "class_cycling_fundamentals",
        name: "Cycling Fundamentals",
        description: "Beginner-friendly coached cycling class.",
      },
      {
        class_id: "class_city_guided_tour",
        name: "City Guided Tour",
        description: "Guided outdoor city tour with curated stops.",
      },
    ] as const;

    for (const classSeed of classSeeds) {
      const existingClass = await ctx.db
        .query("classes")
        .withIndex("by_class_id", (q) => q.eq("class_id", classSeed.class_id))
        .first();

      if (!existingClass) {
        await ctx.db.insert("classes", {
          ...classSeed,
          status: "active",
          created_at: now,
        });
        classesCreated += 1;
      }
    }

    const sessionSeeds = [
      {
        session_id: "session_cycling_2026_03_15_0900",
        class_id: "class_cycling_fundamentals",
        location: "Downtown Studio A",
        date: "2026-03-15",
        time: "09:00",
        quota_defined: 20,
      },
      {
        session_id: "session_cycling_2026_03_22_0900",
        class_id: "class_cycling_fundamentals",
        location: "Downtown Studio A",
        date: "2026-03-22",
        time: "09:00",
        quota_defined: 20,
      },
      {
        session_id: "session_tour_2026_03_16_1400",
        class_id: "class_city_guided_tour",
        location: "City Hall Entrance",
        date: "2026-03-16",
        time: "14:00",
        quota_defined: 15,
      },
      {
        session_id: "session_tour_2026_03_23_1400",
        class_id: "class_city_guided_tour",
        location: "City Hall Entrance",
        date: "2026-03-23",
        time: "14:00",
        quota_defined: 15,
      },
    ] as const;

    for (const sessionSeed of sessionSeeds) {
      const existingSession = await ctx.db
        .query("sessions")
        .withIndex("by_session_id", (q) =>
          q.eq("session_id", sessionSeed.session_id)
        )
        .first();

      if (!existingSession) {
        await ctx.db.insert("sessions", {
          ...sessionSeed,
          quota_used: 0,
          status: "scheduled",
          created_at: now,
        });
        sessionsCreated += 1;
      }
    }

    const existingCurrentTerms = await ctx.db
      .query("terms_versions")
      .withIndex("by_is_current", (q) => q.eq("is_current", true))
      .first();

    if (!existingCurrentTerms) {
      await ctx.db.insert("terms_versions", {
        version: "v1.0",
        content:
          "By participating, you agree to follow instructor guidance and acknowledge standard activity risks.",
        is_current: true,
        created_at: now,
      });
      termsCreated += 1;
    }

    const adminSeeds = [
      { username: "admin", role: "super_admin", password: "admin123" },
      { username: "staff", role: "regular_admin", password: "staff123" },
    ] as const;

    for (const adminSeed of adminSeeds) {
      const existingAdmin = await ctx.db
        .query("admins")
        .withIndex("by_username", (q) => q.eq("username", adminSeed.username))
        .first();

      if (!existingAdmin) {
        await ctx.db.insert("admins", {
          username: adminSeed.username,
          role: adminSeed.role,
          password_hash: bcrypt.hashSync(adminSeed.password, 10),
          created_at: now,
        });
        adminsCreated += 1;
      }
    }

    return {
      classes_created: classesCreated,
      sessions_created: sessionsCreated,
      terms_created: termsCreated,
      admins_created: adminsCreated,
    };
  },
});

import { ConvexHttpClient } from "convex/browser";

export function createConvexHttpClient() {
  const deploymentUrl = resolveConvexDeploymentUrl();
  return new ConvexHttpClient(deploymentUrl, { logger: false });
}

function resolveConvexDeploymentUrl(): string {
  const fromEnv =
    process.env.NEXT_PUBLIC_CONVEX_URL ??
    process.env.CONVEX_URL ??
    process.env.NEXT_CONVEX_URL;

  if (!fromEnv) {
    throw new Error(
      "Missing Convex URL. Set NEXT_PUBLIC_CONVEX_URL (or CONVEX_URL) to your deployment URL."
    );
  }

  return fromEnv.trim().replace(/\/+$/, "");
}
